// @ts-check
import { defineStore } from 'pinia'

export const useWsStore = defineStore({
    id: 'ws',
    state: () => ({
        wsInstance: null,
        connected: false,
        connectRetryCount: 0,
        privateParams: {},
        publicParams: {},
        autoFollowStatus: {},
        status:{},
        simulationStatus: {},
        faultStatus: {},
        shearer: {},
        lockStatus: {},
        actionStatus:{}
        // sendDataNum :0,
        // receiveDataRightNum:0,
        // receiveDataNum:0,
        // receiveDataErrorNum:0,
        // sendDataBitNum:0,
        // receiveDataRightBitNum:0,
        // receiveDataBitNum:0,
        // receiveDataErrorBitNum:0,
        // ErrorRate:0,

    }),
    actions: {

        init() {
            this.connect()
        },
        connect() {
            console.log("进入websocket")
            
            const protocol = window.location.protocol
            console.log("protocol")
            console.log("protocol",protocol)
            let url = "";
            if (protocol=="http:"){
                url = `ws://${window.location.host}/ws`;
            }else if (protocol=="https:"){
                url = `wss://${window.location.host}/ws`;
            }
            
            this.wsInstance = new WebSocket(url);
            let that = this
            //连接断开后操作
            this.wsInstance.onclose = () => {
                that.connected = false
                that.connectRetryCount++;
                setTimeout(() => {
                    that.connect();
                }, 1000 * that.connectRetryCount);
            };
            this.wsInstance.onerror = () => {
                this.wsInstance.close()
            }
            //连接打开，可以发送消息
            this.wsInstance.onopen = () => {
                this.connected = true
                this.connectRetryCount = 0;
            }
            // TODO ： 增加消息处理，消息接收和发送
            this.wsInstance.onmessage = async (/** @type {any} */ msg) => {
                //console.log("@@@",msg)
                let jsonData = JSON.parse(msg.data)
                if (jsonData.type == "privateparam") {
                    this.privateParams = jsonData
                    //console.log('@@',jsonData)
                }
                if (jsonData.type == "publicparam") {
                    this.publicParams = jsonData.msg
                    //console.log("aa",jsonData.msg)
                }
                if (jsonData.type == "autoFollowStatus") {
                    this.autoFollowStatus = jsonData.msg
                }
                if (jsonData.type == "status") {
                    this.status = jsonData.msg
                }
                if (jsonData.type == "simulationStatus") {
                    this.simulationStatus = jsonData.msg
                }
                if (jsonData.type == "faultStatus") {
                    this.faultStatus = jsonData.msg
                }
                
                if (jsonData.type == "shearer") {
                    this.shearer = jsonData.msg
                }
                if (jsonData.type == "lockStatus") {
                    this.lockStatus = jsonData
                }
                if (jsonData.type == "actionStatus") {
                    this.actionStatus = jsonData
                }



                
                // if (jsonData.type == "wml") {
                //    let{sendDataNum ,
                //     receiveDataRightNum,
                //     receiveDataNum,
                //     receiveDataErrorNum,
                //     sendDataBitNum,
                //     receiveDataRightBitNum,
                //     receiveDataBitNum,
                //     receiveDataErrorBitNum,
                //     ErrorRate,
                //    }=jsonData.msg
                //    this.sendDataNum = sendDataNum
                //    this.receiveDataRightNum = receiveDataRightNum
                //    this.receiveDataNum = receiveDataNum
                //    this.receiveDataErrorNum =receiveDataErrorNum 
                //    this.sendDataBitNum = sendDataBitNum
                //    this.receiveDataRightBitNum = receiveDataRightBitNum
                //    this.receiveDataBitNum = receiveDataBitNum
                //    this.receiveDataErrorBitNum = receiveDataErrorBitNum
                //    this.ErrorRate = ErrorRate

                // }
              
            }
        },
    }
})