<template>
  <n-scrollbar ref="scrollbarRef" trigger="none" x-scrollable >
    <div class="scollbar-footer">
      <span
        class="scollbar-footer-content"
        v-for="id in supports"
        :key="id"
        @click="emitSelect(id)"
      >
        <n-badge :color="active_array.includes(id) ?'green' :'gray'" :value="id">
          <n-icon size="40" class="scollbar-footer-icon">
            <svg
              t="1643168915172"
              class="icon"
              viewBox="0 0 1024 1024"
              version="1.1"
              xmlns="http://www.w3.org/2000/svg"
              p-id="6703"
              width="32"
              height="32"
            >
              <path
                d="M148.371 608.857c36.75 10.619 65.824 23.573 90.561 45.519-1.578-14.262-5.848-22.886-16.254-38.598h156.115v-14.91H222.999c10.284-14.771 15.404-24.398 15.932-37.529-23.395 22.632-53.81 34.431-90.56 45.518z m611.432-336.135v-17.035l-16.316-10.591-665.617 5.293c-19.401 6.3-5.439 42.385-5.439 42.385l4.135 0.257c-1.47 7.304-3.124 19.943 1.304 26.223 6.444 9.158 10.872 10.605 10.872 10.605L284.52 441.104h10.875l5.436-10.591v-10.591L108.509 295.015l310.131 19.262 24.709 96.276-15.275 4.057 30.79 119.966-9.034 1.887 38.066 174.813H335.628l-48.944 21.186-108.763-5.297-10.872 10.605v52.974H825.06v-63.579l-17.646-31.514c18.237-25.832 42.782-61.566 57.948-83.737l8.642 9.315h48.944l32.622-31.791v-84.765L759.803 272.722zM629.286 610.623v84.765l-32.627 15.889h-16.316l-54.38-190.715-6.45 1.347-31.616-123.186-11.485 3.05-23.052-85.339 45.414 2.821 21.753 37.085h107.709l144.579 155.826-114.842 98.458h-28.687z m156.608 46.595l-26.09-46.594H718.97c27.79-25.774 62.91-59.091 77.5-72.962l44.194 47.632-54.77 71.924z"
                p-id="6704"
                fill="#e6e6e6"
              />
            </svg>
          </n-icon>
        </n-badge>
      </span>
      
    </div>
  </n-scrollbar>
</template>

<script setup>
import { onMounted, reactive, ref } from "vue";
import { getSupportNum,getSupportPosition  } from "../api/request";
const props = defineProps({
  active: Number,
  total: Number,
  group_enable:Boolean
});

let count = ref(1);
let start_n=ref(0)
let end_n=ref(0)
let active_array=ref([1,1]);
const emits = defineEmits(["selected"]);
const emitSelect = (key) => {
    if(props.group_enable){
      console.log("编组使能已开放")
      if(count.value == 1){
      selected_id.value  = key
      start_n.value = key
      console.log('触发',start_n.value) 
      emits("selected", [start_n.value,start_n.value]);
      active_array.value = [start_n.value]
    }else if(count.value == 3){
      selected_id.value  = key
      start_n.value = key
      console.log('触发',[start_n.value,start_n.value]) 
      emits("selected", [start_n.value,start_n.value]);
      count.value = 1
      active_array.value = [start_n.value]
    }else if(count.value == 2){
      end_n.value = key 
      console.log('触发',end_n.value)
      emits("selected", [start_n.value,end_n.value]);  
      active_array.value = Array.from({ length: Math.abs(end_n.value-start_n.value)+1 }, (_, index) => start_n.value + (end_n.value > start_n.value? index : -index))
    }
    
    count.value += 1
    
    console.log('触发',active_array.value)
  }else{
      console.log("编组使能已关闭")
      selected_id.value  = key
      start_n.value = key
      console.log('触发',start_n.value) 
      emits("selected", [start_n.value,start_n.value]);
      active_array.value = [start_n.value]
  }
  
  
};

onMounted(async () => {
  
  // start_n.value = 1
  // emits("selected", [start_n.value,start_n.value]);
  let {code,message} = await getSupportNum();
  supports.value = Array.from({ length: message}).map((v, k) => k + 1)
  let {code1,message1} = await getSupportPosition();
  if (message1==0){
      selected_id.value = 1
  }else{
      selected_id.value = message1/10
  }
  emits("selected", [selected_id.value,selected_id.value]);
  
  if (selected_id.value>17){
      scrollbarRef.value.scrollTo({ left:63*(selected_id.value-17), behavior: 'auto' })
  }

  // setInterval( async ()=>{
  
  //   console.log("获取煤机位置数据",props.active)
   
  // },1000);
 
});
const supports = ref(Array.from({ length: props.total }).map((v, k) => k + 1));
const selected_id = ref(props.active)
const scrollbarRef = ref(null);



</script>

<style lang="scss" scoped>
.scollbar-footer {
  padding-top: 15px;
  height: 30px;
  white-space: nowrap;
  text-align: center;
  &-content {
    margin: 10px;
    justify-content: center;
  }
  &-icon {
    color: azure;
  }
  .n-badge {
    cursor: pointer;
  }
}
</style>