// @ts-check
import { defineStore } from 'pinia'

export const messageModelStore = defineStore({
    id: 'message',
    state: () => ({
        useMessage: null,
        useNitification: null,
    }),
    actions: {
        setUseMessage(usemessage) {
            this.useMessage = usemessage
        },
        setUseNotification(usenotify) {
            this.useNitification = usenotify
        }
    },
})